class AddCustomSolanaTokenView extends ConsumerStatefulWidget {
  const AddCustomSolanaTokenView({
    super.key,
    this.walletId,
  });

  static const routeName = "/addCustomSolanaToken";

  final String? walletId;

  @override
  ConsumerState<AddCustomSolanaTokenView> createState() =>
      _AddCustomSolanaTokenViewState();
}

class _AddCustomSolanaTokenViewState
    extends ConsumerState<AddCustomSolanaTokenView> {
  final isDesktop = Util.isDesktop;

  final mintController = TextEditingController();
  final nameController = TextEditingController();
  final symbolController = TextEditingController();
  final decimalsController = TextEditingController();

  bool enableSubFields = false;
  bool addTokenButtonEnabled = false;

  SplToken? currentToken;

  Future<void> _searchTokenMetadata() async {
    debugPrint('[ADD_CUSTOM_SOLANA_TOKEN] Search button pressed');

    // Validate mint address format first.
    final tokenApi = SolanaTokenAPI();
    final isValid = tokenApi.isValidSolanaMintAddress(
      mintController.text.trim(),
    );

    debugPrint('[ADD_CUSTOM_SOLANA_TOKEN] Mint address valid: $isValid');

    // Check if token is already in the wallet.
    if (widget.walletId != null) {
      final walletInfo = ref.watch(pWalletInfo(widget.walletId!));
      final allTokenMints = <String>{
        ...walletInfo.solanaTokenMintAddresses,
        ...walletInfo.solanaCustomTokenMintAddresses,
      };

      if (allTokenMints.contains(mintController.text.trim())) {
        debugPrint('[ADD_CUSTOM_SOLANA_TOKEN] Token already in wallet');
        setState(() {
          addTokenButtonEnabled = false;
        });
        // Show error dialog for duplicate token.
        if (mounted) {
          unawaited(
            showDialog<void>(
              context: context,
              builder: (dialogContext) => ConditionalParent(
                condition: Util.isDesktop,
                builder: (child) => DesktopDialog(
                  maxWidth: 500,
                  maxHeight: double.infinity,
                  child: Padding(
                    padding: const EdgeInsets.all(32),
                    child: child,
                  ),
                ),
                child: ConditionalParent(
                  condition: !Util.isDesktop,
                  builder: (child) => StackDialogBase(child: child),
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Text(
                        "Token Already Added",
                        style: STextStyles.pageTitleH2(context),
                      ),
                      const SizedBox(height: 8),
                      Text(
                        "This token is already in your wallet.",
                        style: STextStyles.smallMed14(context),
                      ),
                      const SizedBox(height: 20),
                      Row(
                        children: [
                          const Spacer(),
                          Expanded(
                            child: PrimaryButton(
                              label: "OK",
                              onPressed: () => Navigator.of(dialogContext).pop(),
                            ),
                          ),
                        ],
                      ),
                    ],
                  ),
                ),
              ),
            ),
          );
        }
        return;
      }
    }

    if (!isValid) {
      setState(() {
        addTokenButtonEnabled = false;
      });
      // Show error dialog for invalid address.
      if (mounted) {
        unawaited(
          showDialog<void>(
            context: context,
            builder: (dialogContext) => ConditionalParent(
              condition: Util.isDesktop,
              builder: (child) => DesktopDialog(
                maxWidth: 500,
                maxHeight: double.infinity,
                child: Padding(
                  padding: const EdgeInsets.all(32),
                  child: child,
                ),
              ),
              child: ConditionalParent(
                condition: !Util.isDesktop,
                builder: (child) => StackDialogBase(child: child),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Text(
                      "Invalid Mint Address",
                      style: STextStyles.pageTitleH2(context),
                    ),
                    const SizedBox(height: 8),
                    Text(
                      "Please enter a valid Solana SPL token mint address (base58 encoded, ~44 characters).",
                      style: STextStyles.smallMed14(context),
                    ),
                    const SizedBox(height: 20),
                    Row(
                      children: [
                        const Spacer(),
                        Expanded(
                          child: PrimaryButton(
                            label: "OK",
                            onPressed: () => Navigator.of(dialogContext).pop(),
                          ),
                        ),
                      ],
                    ),
                  ],
                ),
              ),
            ),
          ),
        );
      }
      return;
    }

    // Fetch token metadata.
    debugPrint('[ADD_CUSTOM_SOLANA_TOKEN] Fetching metadata for mint: ${mintController.text.trim()}');
    final response =
        await tokenApi.fetchTokenMetadataByMint(mintController.text.trim());

    if (!mounted) return;

    debugPrint('[ADD_CUSTOM_SOLANA_TOKEN] Metadata response: ${response.value}');

    if (response.value != null && response.value!.isNotEmpty) {
      final metadata = response.value!;
      currentToken = SplToken(
        address: mintController.text.trim(),
        name: metadata['name'] as String? ?? 'Unknown Token',
        symbol: metadata['symbol'] as String? ?? '???',
        decimals: metadata['decimals'] as int? ?? 6,
        logoUri: metadata['logoUri'] as String?,
      );

      nameController.text = currentToken!.name;
      symbolController.text = currentToken!.symbol;
      decimalsController.text = currentToken!.decimals.toString();

      // Disable editing when we have metadata.
      setState(() {
        enableSubFields = false;
        addTokenButtonEnabled = currentToken != null;
      });
      debugPrint('[ADD_CUSTOM_SOLANA_TOKEN] Metadata found, fields populated');
    } else {
      // Token not found, allow user to manually enter details.
      debugPrint('[ADD_CUSTOM_SOLANA_TOKEN] Metadata not found, enabling manual entry');
      nameController.text = "";
      symbolController.text = "";
      decimalsController.text = "";

      // Enable fields for manual entry and allow user to create token with custom values.
      setState(() {
        enableSubFields = true;
        currentToken = SplToken(
          address: mintController.text.trim(),
          name: '',
          symbol: '',
          decimals: 6,
          logoUri: null,
        );
        // Allow adding token once mint is validated.
        addTokenButtonEnabled = true;
      });

      // Show dialog for manual entry & alert the user they need to enter details manually.
      if (mounted) {
        unawaited(
          showDialog<void>(
            context: context,
            builder: (dialogContext) => ConditionalParent(
              condition: Util.isDesktop,
              builder: (child) => DesktopDialog(
                maxWidth: 500,
                maxHeight: double.infinity,
                child: Padding(
                  padding: const EdgeInsets.all(32),
                  child: child,
                ),
              ),
              child: ConditionalParent(
                condition: !Util.isDesktop,
                builder: (child) => StackDialogBase(child: child),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Text(
                      "Metadata Not Found",
                      style: STextStyles.pageTitleH2(context),
                    ),
                    const SizedBox(height: 8),
                    Text(
                      "Could not fetch token metadata. Please enter the token details manually below.",
                      style: STextStyles.smallMed14(context),
                    ),
                    const SizedBox(height: 20),
                    Row(
                      children: [
                        const Spacer(),
                        Expanded(
                          child: PrimaryButton(
                            label: "OK",
                            onPressed: () => Navigator.of(dialogContext).pop(),
                          ),
                        ),
                      ],
                    ),
                  ],
                ),
              ),
            ),
          ),
        );
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    return ConditionalParent(
      condition: !isDesktop,
      builder: (child) => Background(
        child: Scaffold(
          backgroundColor: Theme.of(
            context,
          ).extension<StackColors>()!.background,
          appBar: AppBar(
            leading: AppBarBackButton(
              onPressed: () {
                Navigator.of(context).pop();
              },
            ),
          ),
          body: SafeArea(
            child: Padding(
              padding: const EdgeInsets.only(
                top: 10,
                left: 16,
                right: 16,
                bottom: 16,
              ),
              child: child,
            ),
          ),
        ),
      ),
      child: ConditionalParent(
        condition: isDesktop,
        builder: (child) => Column(
          children: [
            Row(
              mainAxisAlignment: MainAxisAlignment.spaceBetween,
              children: [
                Padding(
                  padding: const EdgeInsets.only(left: 32),
                  child: Text(
                    "Add custom SPL token",
                    style: STextStyles.desktopH3(context),
                  ),
                ),
                const DesktopDialogCloseButton(),
              ],
            ),
            Flexible(
              child: Padding(
                padding: const EdgeInsets.only(
                  left: 32,
                  right: 32,
                  bottom: 32,
                  top: 16,
                ),
                child: child,
              ),
            ),
          ],
        ),
        child: Column(
          children: [
            if (!isDesktop)
              Text(
                "Add custom SPL token",
                style: STextStyles.pageTitleH1(context),
              ),
            if (!isDesktop) const SizedBox(height: 16),
            TextField(
              autocorrect: !isDesktop,
              enableSuggestions: !isDesktop,
              controller: mintController,
              style: STextStyles.field(context),
              decoration: InputDecoration(
                hintText: "SPL token mint address",
                hintStyle: STextStyles.fieldLabel(context),
              ),
            ),
            SizedBox(height: isDesktop ? 16 : 8),
            PrimaryButton(
              label: "Search",
              onPressed: _searchTokenMetadata,
            ),
            SizedBox(height: isDesktop ? 16 : 8),
            TextField(
              enabled: enableSubFields,
              autocorrect: !isDesktop,
              enableSuggestions: !isDesktop,
              controller: nameController,
              style: STextStyles.field(context),
              decoration: InputDecoration(
                hintText: "Token name",
                hintStyle: STextStyles.fieldLabel(context),
              ),
            ),
            SizedBox(height: isDesktop ? 16 : 8),
            if (isDesktop)
              Row(
                children: [
                  Expanded(
                    child: TextField(
                      enabled: enableSubFields,
                      autocorrect: !isDesktop,
                      enableSuggestions: !isDesktop,
                      controller: symbolController,
                      style: STextStyles.field(context),
                      decoration: InputDecoration(
                        hintText: "Ticker",
                        hintStyle: STextStyles.fieldLabel(context),
                      ),
                    ),
                  ),
                  const SizedBox(width: 16),
                  Expanded(
                    child: TextField(
                      enabled: enableSubFields,
                      autocorrect: !isDesktop,
                      enableSuggestions: !isDesktop,
                      controller: decimalsController,
                      style: STextStyles.field(context),
                      inputFormatters: [
                        TextInputFormatter.withFunction(
                          (oldValue, newValue) =>
                              RegExp(r'^([0-9]*)$').hasMatch(newValue.text)
                              ? newValue
                              : oldValue,
                        ),
                      ],
                      keyboardType: const TextInputType.numberWithOptions(
                        signed: false,
                        decimal: false,
                      ),
                      decoration: InputDecoration(
                        hintText: "Decimals",
                        hintStyle: STextStyles.fieldLabel(context),
                      ),
                    ),
                  ),
                ],
              ),
            if (!isDesktop)
              TextField(
                enabled: enableSubFields,
                autocorrect: !isDesktop,
                enableSuggestions: !isDesktop,
                controller: symbolController,
                style: STextStyles.field(context),
                decoration: InputDecoration(
                  hintText: "Ticker",
                  hintStyle: STextStyles.fieldLabel(context),
                ),
              ),
            if (!isDesktop) const SizedBox(height: 8),
            if (!isDesktop)
              TextField(
                enabled: enableSubFields,
                autocorrect: !isDesktop,
                enableSuggestions: !isDesktop,
                controller: decimalsController,
                style: STextStyles.field(context),
                inputFormatters: [
                  TextInputFormatter.withFunction(
                    (oldValue, newValue) =>
                        RegExp(r'^([0-9]*)$').hasMatch(newValue.text)
                        ? newValue
                        : oldValue,
                  ),
                ],
                keyboardType: const TextInputType.numberWithOptions(
                  signed: false,
                  decimal: false,
                ),
                decoration: InputDecoration(
                  hintText: "Decimals",
                  hintStyle: STextStyles.fieldLabel(context),
                ),
              ),
            const SizedBox(height: 16),
            const Spacer(),
            Row(
              children: [
                if (isDesktop)
                  Expanded(
                    child: SecondaryButton(
                      label: "Cancel",
                      onPressed: Navigator.of(context).pop,
                    ),
                  ),
                if (isDesktop) const SizedBox(width: 16),
                Expanded(
                  child: PrimaryButton(
                    label: "Add token",
                    enabled: addTokenButtonEnabled,
                    onPressed: () {
                      // Update currentToken with user-entered values.
                      if (currentToken != null) {
                        final finalToken = currentToken!.copyWith(
                          name: nameController.text.isNotEmpty
                              ? nameController.text
                              : currentToken!.name,
                          symbol: symbolController.text.isNotEmpty
                              ? symbolController.text
                              : currentToken!.symbol,
                          decimals: decimalsController.text.isNotEmpty
                              ? int.tryParse(decimalsController.text) ??
                                  currentToken!.decimals
                              : currentToken!.decimals,
                        );
                        Navigator.of(context).pop(finalToken);
                      }
                    },
                  ),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }

  @override
  void dispose() {
    mintController.dispose();
    nameController.dispose();
    symbolController.dispose();
    decimalsController.dispose();
    super.dispose();
  }
}
